mapper.select:
SELECT i.id, i.audit_log_id, i.user_id, i.model, i.prompt_tokens, i.completion_tokens, i.insight_json,
       i.created_at, i.updated_at
FROM analytics_llm_insight i
INNER JOIN analytics_audit_log a ON a.id = i.audit_log_id
WHERE a.user_id = #{userId}
  AND a.view_id = #{viewId}

mapper.insert:
INSERT INTO analytics_llm_insight (
    audit_log_id, user_id, model, prompt_tokens, completion_tokens, insight_json
) VALUES (
    #{auditLogId}, #{userId}, #{model}, #{promptTokens}, #{completionTokens}, #{insightJson}
)
